<article class="product-card"><a href="<?=u('/app/entry/'.(int)$entry['id'])?>" aria-label="<?=e($entry['product_name'])?> öffnen"><div class="product-image"><?php if(product_img($entry['image_url']??'')):?><img src="<?=e(product_img($entry['image_url']))?>" alt="<?=e($entry['product_name'])?>" loading="lazy"><?php else:?><span class="image-fallback" aria-hidden="true">▦</span><?php endif;?><b class="rating-badge"><?=e($entry['overall_rating'])?></b></div><div class="product-card-copy"><p class="card-kicker"><?=e($entry['brand']?:'Ohne Marke')?></p><h3><?=e($entry['product_name'])?></h3><div class="product-flags"><?php if($entry['favorite']):?><span>Favorit</span><?php endif;?><?php if($entry['buy_again']==='yes'):?><span>Wieder kaufen</span><?php endif;?><?php if($entry['movie_night']):?><span>Filmabend</span><?php endif;?><?php if($entry['never_again']):?><span class="flag-no">Nie wieder</span><?php endif;?></div></div></a></article>
